import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionSecure {

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter a command to execute: ");
        String userInput = br.readLine();

        // Sanitize user input to allow only alphanumeric characters and whitelist certain safe characters
        if (!userInput.matches("[a-zA-Z0-9.-]+")) {
            System.out.println("Invalid input. Only alphanumeric characters, dots, and hyphens are allowed.");
            return;
        }

        // Execute the sanitized command using ProcessBuilder
        ProcessBuilder pb = new ProcessBuilder(userInput.split(" "));
        Process process = pb.start();

        BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String line;
        while ((line = reader.readLine()) != null) {
            System.out.println(line);
        }
    }
}

